&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(32, 33, 36); font-variant-ligatures: none; letter-spacing: 0.1px; white-space: pre-wrap; &quot;&gt;Option 2:&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

